<template><view class="page" v-if="doctor"><view class="profile"><view class="avatar">{{doctor.name.slice(0,1)}}</view><text class="name">{{doctor.name}}</text><text class="meta">{{doctor.title||'医师'}} · {{doctor.departmentName||'综合门诊'}}</text><view class="stats"><view><b>8+</b><text>从业年限</text></view><view><b>98%</b><text>患者好评</text></view><view><b>4.9</b><text>综合评分</text></view></view></view><view class="card"><text class="heading">擅长领域</text><text class="copy">{{doctor.specialty||'常见病、多发病的规范化诊疗与健康管理'}}</text></view><view class="card"><text class="heading">医生简介</text><text class="copy">{{doctor.introduction||'秉持专业、耐心、负责的诊疗理念，为患者提供高质量医疗服务。'}}</text></view><view class="bottom"><button @tap="book">立即预约</button></view></view></template>
<script setup lang="ts">import{ref}from'vue';import{onLoad}from'@dcloudio/uni-app';import{getDoctorDetail}from'@/api/patient';import{showError}from'@/utils/request';import type{Doctor}from'@/types/api';const doctor=ref<Doctor>();onLoad(async q=>{try{doctor.value=await getDoctorDetail(Number(q?.id))}catch(e){showError(e)}});const book=()=>uni.navigateTo({url:`/pages/booking/confirm?doctorId=${doctor.value?.id}`})</script>
<style scoped>.page{padding:32rpx 30rpx 180rpx}.profile{background:linear-gradient(145deg,#075f72,#15958e);color:#fff;border-radius:36rpx;padding:42rpx 30rpx;text-align:center}.avatar{margin:auto;width:128rpx;height:128rpx;border-radius:42rpx;background:rgba(255,255,255,.2);display:flex;align-items:center;justify-content:center;font-size:48rpx}.name{display:block;font-size:38rpx;font-weight:750;margin:22rpx 0 8rpx}.meta{font-size:24rpx;opacity:.8}.stats{display:flex;margin-top:36rpx;padding-top:28rpx;border-top:1rpx solid rgba(255,255,255,.2)}.stats view{flex:1}.stats b,.stats text{display:block}.stats b{font-size:29rpx}.stats text{font-size:19rpx;opacity:.7;margin-top:7rpx}.card{background:#fff;border-radius:28rpx;padding:30rpx;margin-top:24rpx}.heading{display:block;font-size:29rpx;font-weight:700;margin-bottom:15rpx}.copy{font-size:24rpx;line-height:1.8;color:#71848d}.bottom{position:fixed;bottom:0;left:0;right:0;background:#fff;padding:20rpx 30rpx calc(20rpx + env(safe-area-inset-bottom));box-shadow:0 -8rpx 30rpx rgba(20,52,65,.08)}button{background:#087f84;color:#fff;border-radius:24rpx;font-size:29rpx}</style>
